SELECT (COALESCE(price, 3.0) - 3.0) / NULLIF(1.5811388300841898, 0) AS price, (COALESCE(quantity, 35.0) - 32.5) / NULLIF(14.79019945774904, 0) AS quantity, CASE WHEN COALESCE(city, 'London') = 'London' THEN 1 ELSE 0 END AS city_london, CASE WHEN COALESCE(city, 'London') = 'Paris' THEN 1 ELSE 0 END AS city_paris, CASE WHEN COALESCE(city, 'London') = 'Tokyo' THEN 1 ELSE 0 END AS city_tokyo FROM __input__
